import React from "react";
import { BrowserRouter as Router, Routes, Route, useLocation } from "react-router-dom";

// Public Pages
import HeroSection from "./landingpage/HeroSection";
import HowItWorks from "./landingpage/HowItWork";
import FeatureSection from "./landingpage/FeatureSection";
import WhyChooseUs from "./landingpage/WhyChooseUs";
import Testimonials from "./landingpage/Testimonials";
import CTA from "./landingpage/CTASection";
import Footer from "./landingpage/Footer";
import AuthPage from "./AuthPage";

// Dashboard Components
import Sidebar from "./components/dashboard/Sidebar";

// A simple wrapper to handle the Dashboard Layout
const DashboardLayout = ({ children }) => (
  <div style={{ display: 'flex', minHeight: '100vh', background: '#020617' }}>
    <Sidebar />
    <main style={{ flex: 1, padding: '40px', overflowY: 'auto' }}>
      {children}
    </main>
  </div>
);

function LandingPage() {
  return (
    <>
      <HeroSection />
      <HowItWorks />
      <FeatureSection />
      <WhyChooseUs />
      <Testimonials />
      <CTA />
    </>
  );
}

function AppContent() {
  const location = useLocation();
  
  // Check if we are on a dashboard-related route
  const isDashboardRoute = location.pathname.startsWith('/dashboard') || 
                           location.pathname.startsWith('/try-on') ||
                           location.pathname.startsWith('/profile');

  return (
    <div className="App">
      {!isDashboardRoute && (
        <main>
          <Routes>
            <Route path="/" element={<LandingPage />} />
            <Route path="/auth" element={<AuthPage />} />
          </Routes>
        </main>
      )}

      {isDashboardRoute && (
        <DashboardLayout>
          <Routes>
            <Route path="/dashboard" element={<div>Welcome to your Dashboard Home</div>} />
            <Route path="/try-on" element={<div>AI Virtual Try-On Module</div>} />
            <Route path="/profile" element={<div>User Profile Settings</div>} />
            {/* Add more dashboard routes here */}
          </Routes>
        </DashboardLayout>
      )}

      {/* Only show landing page footer on non-dashboard routes */}
      {!isDashboardRoute && <Footer />}
    </div>
  );
}

function App() {
  return (
    <Router>
      <AppContent />
    </Router>
  );
}

export default App;
